import type * as DMMF from '@prisma/dmmf'
import { applyFieldModifiers, prismaTypeToTs } from '../prisma-type-to-ts'

/** Returns true for fields that carry scalar or enum data (i.e. REST-serializable). */
function isDataField(field: DMMF.Field): boolean {
  return field.kind === 'scalar' || field.kind === 'enum'
}

/**
 * Returns true for fields that should be omitted from create/update inputs
 * because their value is managed automatically by the database or Prisma.
 */
function isAutoManagedField(field: DMMF.Field): boolean {
  return Boolean(field.isReadOnly || field.isGenerated || field.isUpdatedAt)
}

function indent(lines: string): string {
  return lines
    .split('\n')
    .map((line) => (line.length > 0 ? `  ${line}` : line))
    .join('\n')
}

function generateEnums(enums: readonly DMMF.DatamodelEnum[]): string {
  if (enums.length === 0) return ''

  const declarations = enums.map((e) => {
    const values = e.values.map((v) => `'${v.name}'`).join(' | ')
    return `export type ${e.name} = ${values}`
  })

  return declarations.join('\n') + '\n'
}

function generateModelInterface(model: DMMF.Model): string {
  const fields = model.fields.filter(isDataField)
  const properties = fields.map((field) => {
    const baseType = prismaTypeToTs(field.type)
    const fullType = applyFieldModifiers(baseType, field.isList, field.isRequired)
    return `${field.name}: ${fullType}`
  })

  return `export interface ${model.name} {\n${indent(properties.join('\n'))}\n}`
}

function generateWhereUniqueInput(model: DMMF.Model): string {
  const fields = model.fields.filter((f) => isDataField(f) && (f.isId || f.isUnique))
  if (fields.length === 0) return ''

  const properties = fields.map((field) => {
    const baseType = prismaTypeToTs(field.type)
    const fullType = applyFieldModifiers(baseType, field.isList, true)
    return `${field.name}?: ${fullType}`
  })

  return `export interface ${model.name}WhereUniqueInput {\n${indent(properties.join('\n'))}\n}`
}

function generateCreateInput(model: DMMF.Model): string {
  const fields = model.fields.filter((f) => isDataField(f) && !isAutoManagedField(f))
  const properties = fields.map((field) => {
    const baseType = prismaTypeToTs(field.type)
    const isOptional = field.hasDefaultValue || !field.isRequired
    const fullType = applyFieldModifiers(baseType, field.isList, field.isRequired)
    const optMark = isOptional ? '?' : ''
    return `${field.name}${optMark}: ${fullType}`
  })

  return `export interface ${model.name}CreateInput {\n${indent(properties.join('\n'))}\n}`
}

function generateUpdateInput(model: DMMF.Model): string {
  const fields = model.fields.filter((f) => isDataField(f) && !isAutoManagedField(f))
  const properties = fields.map((field) => {
    const baseType = prismaTypeToTs(field.type)
    const fullType = applyFieldModifiers(baseType, field.isList, field.isRequired)
    return `${field.name}?: ${fullType}`
  })

  return `export interface ${model.name}UpdateInput {\n${indent(properties.join('\n'))}\n}`
}

function generateFindManyParams(model: DMMF.Model): string {
  return [
    `export interface ${model.name}FindManyParams {`,
    `  skip?: number`,
    `  take?: number`,
    `  orderBy?: Partial<Record<keyof ${model.name}, 'asc' | 'desc'>>`,
    `}`,
  ].join('\n')
}

/** Generates the complete `types.ts` file content for the given DMMF document. */
export function createTypesFile(dmmf: DMMF.Document): string {
  const sections: string[] = []

  const enumSection = generateEnums(dmmf.datamodel.enums)
  if (enumSection) sections.push(enumSection.trimEnd())

  for (const model of dmmf.datamodel.models) {
    sections.push(generateModelInterface(model))
    sections.push(generateWhereUniqueInput(model))
    sections.push(generateCreateInput(model))
    sections.push(generateUpdateInput(model))
    sections.push(generateFindManyParams(model))
  }

  return sections.join('\n\n') + '\n'
}

